INSERT INTO public.photos VALUES (24510, 'Papelera Las Navas 1913', 'Imagen del interior de una de las naves de la gran papelera de Las Navas en el barrio rural de San Juan de Mozarrifar, inaugurada en junio de ese a├▒o. Fuente visual: Luis Gand├║ Mercadal, en "El fot├│grafo Luis Gand├║ Mercadal. Una cr├│nica visual. 1910-1930", Universidad de Zaragoza, 2010.', 1913, 1913, 1913, 'Anos 10', 'SAN JUAN MOZARRIFAR', 41.71876600, -0.83298500, '0101000020E6100000B9DFA128D0A7EABF06BD378600DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33279827554.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33279827554.webp', 'https://www.flickr.com/photos/zaragozaantigua/33279827554/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24544, 'San Juan de Mozarrifar 1913', 'Imagen capturada en el taller de fabricaci├│n de papel de la nueva f├íbrica perteneciente a la donostiarra "Sociedad Espa├▒ola de Papeler├¡a" levantada en San Juan de Mozarrifar. Toda la maquinaria fabril era de fabricaci├│n inglesa, que de los originales fajos de esparto y en un proceso de tratamiento en varias fases resultaba una pasta blanca "con todo el aspecto del reques├│n". En el taller de la imagen, un departamento de grandes proporciones tanto en extensi├│n como altura, la maquinaria se encargaba de transformar en blanco y fino papel la grumosa pasta esparte├▒a, que terminaba convenientemente enrollado en unas grandes bobinas. Por ├║ltimo, se proced├¡a a la operaci├│n de cortar el papel y apilarlo en "resmas" (unidad de conteo de hojas de papel).', 1913, 1913, 1913, 'Anos 10', 'SAN JUAN MOZARRIFAR', 41.71876600, -0.83298500, '0101000020E6100000B9DFA128D0A7EABF06BD378600DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53455135925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53455135925.webp', 'https://www.flickr.com/photos/zaragozaantigua/53455135925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25069, 'Borbones 1986', 'Academia General Militar de Zaragoza, 1986. Felipe, su padre Juan Carlos y su abuelo Juan de Borb├│n. La formaci├│n castrense del primero tuvo lugar en 1985 y 1986, al igual que sucedi├│ con el segundo, entre 1955 y 1957. La estrecha relaci├│n de esta familia con Zaragoza, pues, queda patente, como lo fue en su d├¡a la del que nombr├│ sucesor al de en medio, Francisco Franco, que fue director de la Academia entre 1928 y 1931.', 1986, 1986, 1986, 'Anos 80', NULL, 41.69947400, -0.87186500, '0101000020E610000083DDB06D51E6EBBF7F33315D88D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15220315385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15220315385.webp', 'https://www.flickr.com/photos/zaragozaantigua/15220315385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22522, 'Garrapinillos 1960', 'Fotograma de la pel├¡cula "Alerta en el cielo" rodada en Zaragoza en el oto├▒o de 1960 bajo la direcci├│n de Luis C├®sar Amadori. Aqu├¡ se muestra la pasada de cuatro cazas a reacci├│n modelo F-86 Sabre radicados en la "base conjunta hispano-norteamericana Valenzuela y Sanjurjo" sobre el barrio rural de Garrap├¼nillos, en una escena capturada desde la calle de Pignatelli de esta localidad. El montaje definitivo, sin embargo, presentaba esta escena como si los aviones hubiera pasado por el casco urbano de Zaragoza, dado que el domicilio del ni├▒o protagonista aparece radicado en la antigua plazuela de San Bruno, esquina con la calle del Sepulcro, donde su madre se asoma a la ventana a increpar a los "malditos americanos" por haber despertado al infante. Este resentimiento no era pol├¡tico, por supuesto, sino laboral, dado que su marido no hab├¡a podido "encontrar trabajo" en la base a├®rea, pero no dura demasiado ante la superlativa y ser├ífica bondad norteamericana.', 1960, 1960, 1960, 'Anos 60', 'GARRAPINILLOS', 41.68319200, -1.02610500, '0101000020E61000007B319413ED6AF0BFC571E0D572D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55087227807.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55087227807.webp', 'https://www.flickr.com/photos/zaragozaantigua/55087227807/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22919, 'Garrapinillos 1981', 'Ortofoto de 1981 del barrio rural de Garrapinillos y alrededores. La zona en blanco bajo la parrilla de la Urbanizaci├│n Condefuentes, al sur del camino de B├írboles, corresponder├¡a al aeropuerto de Zaragoza. Fuente: Instituto Geogr├ífico de Arag├│n.', 1981, 1981, 1981, 'Anos 80', 'GARRAPINILLOS', 41.68423200, -1.02861200, '0101000020E6100000D55E44DB3175F0BF377007EA94D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27602125768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27602125768.webp', 'https://www.flickr.com/photos/zaragozaantigua/27602125768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21516, 'Iglesia de Las Casetas c.1920', 'En el peque├▒o pueblo de "Las Casetas", el edificio m├ís destacable se consideraba que era el Palacio del Duque de Solferino, due├▒o de un abundante cat├ílogo de propiedades. Durante la guerra de 1808-1813, en este palacio pernoctar├¡a el Mariscal Suchet, Gobernador General de Arag├│n. La original capilla particular del Palacio, del siglo XVIII, se convirti├│ en la iglesia parroquial del lugar en el siglo XX. Una vez desaparecido el Palacio, el templo perdura, muy reformado, entre dos muy contempor├íneos edificios. En la imagen, la iglesia y el Palacio, a su izquierda. Fuente: Jaime Latas Fuertes, "El Ebro en Los Sitios de Zaragoza", Asociaci├│n Cultural "Los Sitios de Zaragoza", 2006.', 1920, 1920, 1920, 'Anos 20', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15812279290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15812279290.webp', 'https://www.flickr.com/photos/zaragozaantigua/15812279290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21620, 'Las Casetas c.1920', 'Imagen con la fachada del desaparecido palacio del duque de Solferino, localizado en la carretera de Logro├▒o a su paso por las Casetas, y a continuaci├│n, la capilla particular del palacio, del siglo XVIII, desde principios del siglo XX iglesia parroquial del lugar, bajo la advocaci├│n de San Miguel Arc├íngel.', 1920, 1920, 1920, 'Anos 20', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33370616901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33370616901.webp', 'https://www.flickr.com/photos/zaragozaantigua/33370616901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21830, 'Alcal├í Zamora 1934', 'El presidente de la Rep├║blica entre 1931 y 1936, Niceto Alcal├í Zamora, durante su estancia rel├ímpago en el barrio zaragozano de Casetas en 1934, con el tiempo justo de dejar el tren especial que le trajo desde Zaragoza para enlazar con el r├ípido de Madrid. Fuente: Heraldo de Arag├│n.', 1934, 1934, 1934, 'Anos 30', 'CASETAS', 41.72318400, -1.02332900, '0101000020E61000002EC6C03A8E5FF0BFC87E164B91DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33090421002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33090421002.webp', 'https://www.flickr.com/photos/zaragozaantigua/33090421002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22476, 'Ctra. de Logro├▒o c.1965', 'Vista de la carretera de Logro├▒o a su paso por el barrio rural de Casetas centrada en la esquina con la calle del Palacio, a la izquierda, referencia vial al cercano y antiguo palacio del duque de Solferino, a la derecha. Fuente visual: www.todocoleccion.net/', 1965, 1965, 1965, 'Anos 60', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34262000441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34262000441.webp', 'https://www.flickr.com/photos/zaragozaantigua/34262000441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22888, 'Casetas 1980', 'Vista a├®rea del barrio rural de Casetas. Fuente: Zaragoza en im├ígenes, CAZAR, 1980.', 1980, 1980, 1980, 'Anos 80', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20261485035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20261485035.webp', 'https://www.flickr.com/photos/zaragozaantigua/20261485035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23745, 'Estaci├│n de Casetas 2005', 'Imagen de la estaci├│n de tren de Casetas, unos a├▒os antes de su importante transformaci├│n con motivo de la implantaci├│n de la bien poco exitosa l├¡nea de Cercan├¡as que desde aqu├¡ llega a la estaci├│n de Miraflores (y a la inversa). Pese a que en apenas 20 minutos se hace un recorrido de m├ís de 16 km., la poca conectividad e intermodalidad de medios de transporte hace que esta l├¡nea sea algo m├ís que un lujo: un despilfarro. La imagen est├í tomada mirando en direcci├│n hacia Zaragoza (a la izquierda). Fuente visual: www.facebook.com/photo.php?fbid=10204608857455317&set...', 2005, 2005, 2005, 'Siglo XXI', 'CASETAS', 41.72328300, -1.02157800, '0101000020E61000006902452C6258F0BF5B608F8994DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15399504014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15399504014.webp', 'https://www.flickr.com/photos/zaragozaantigua/15399504014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23750, '&quot;Bibliob├║s&quot; en Casetas 1959', 'El "Servicio M├│vil de la Biblioteca P├║blica de la Ciudad", o "Bibliob├║s", fue un servicio bibliotecario regular que desde la autorizaci├│n gubernamental en 1955, y el apoyo de la Direcci├│n General de Archivos y Bibliotecas, del Ministerio de Educaci├│n Nacional, fue prestado por el Ayuntamiento a los "barrios agregados" del extrarradio municipal, mediante una "Biblioteca m├│vil" arrastrada por un "jeep Willys". Desde 1957 esta caravana llevaba regularmente el servicio p├║blico a aquellas zonas rurales de la ciudad que, por su lejan├¡a y escasa poblaci├│n (entre todas apenas llegaban entonces a los 27000 habitantes), no contaban con una biblioteca estable. En la imagen, "Bibliob├║s" instalado en el lateral derecho de la plaza del Castillo de Casetas, junto al edificio de la Casa Alcald├¡a que originalmente albergara las escuelas de ni├▒os y ni├▒as del lugar, edificio dise├▒ado por Ricardo Magdalena a finales del siglo XIX.', 1959, 1959, 1959, 'Anos 50', 'CASETAS', 41.71915100, -1.02718900, '0101000020E6100000A0F99CBB5D6FF0BF5EF1D4230DDC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18731415713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18731415713.webp', 'https://www.flickr.com/photos/zaragozaantigua/18731415713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23752, 'Iglesia de Las Casetas 1976', 'En el peque├▒o pueblo de "Las Casetas", el edificio m├ís destacable se consideraba que era el Palacio del Duque de Solferino, due├▒o del lugar. La original capilla particular de este Palacio, construida a finales del siglo XVIII, se convirti├│ en la iglesia parroquial del lugar, bajo la advocaci├│n de San Miguel, ya en el siglo XX. Una vez desaparecido el Palacio, s├│lo queda el templo, muy reformado y rehabilitado, y emparedado entre dos modernas muestras de la arquitectura local. En la imagen, a la izquierda, la estrecha fachadilla de la iglesia, rematada con su peculiar espada├▒a, y el contempor├íneo edificio que le ha tocado en gracia a su derecha. En sus flancos, vestigios de antiguos edificios del lugar donde se guarec├¡an los antiqu├¡simos pobladores, adem├ís de sus enseres y animales. A los pocos a├▒os ser├ín sustituidos por otras cosas menos provincianas. La imagen se ha tomado desde la antigua carretera de Logro├▒o, hoy v├¡a urbana redenominada "Avenida de Logro├▒o". Fuente: Archivo P├║blico Municipal, Gerardo Sancho Ramo..', 1976, 1976, 1976, 'Anos 70', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19173563441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19173563441.webp', 'https://www.flickr.com/photos/zaragozaantigua/19173563441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23765, 'Casetas c.1960', 'Vista de la carretera de Logro├▒o a su paso por el barrio rural de Casetas, donde perdura el antiguo palacio del duque de Solferino, y su antigua capilla reconvertida en iglesia parroquial de San Miguel. Fuente visual: www.ebay.com/', 1960, 1960, 1960, 'Anos 60', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24958933193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24958933193.webp', 'https://www.flickr.com/photos/zaragozaantigua/24958933193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23768, 'Ctra. de Logro├▒o 1977', 'Lluviosa imagen capturada en la carretera de Logro├▒o a su paso por el barrio de las Casetas, junto a la imponente fachada del que fuera palacio del duque de Solferino. A la derecha del palacio, la iglesia y casa parroquial de San Miguel Arc├íngel. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28096666229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28096666229.webp', 'https://www.flickr.com/photos/zaragozaantigua/28096666229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23772, 'Casetas 1954', 'Vista a├®rea sobre el barrio rural de Casetas. En primer t├®rmino, las enormes instalaciones de la base militar para inspecci├│n y recuperaci├│n de autom├│viles que fue creada durante la guerra de 1936-39, construida con mano de obra esclava formada por prisioneros republicanos, y con entrada principal por la carretera de Logro├▒o. Perdura como Destacamento de Casetas de la Agrupaci├│n de Apoyo Log├¡stico (AALOG) n┬║ 41. Detr├ís, parcelas inmediatas al cauce de la acequia de la Almozara, que mojonea con ├írboles y vegetaci├│n sus m├írgenes. Finalmente, y al fondo, junto a las v├¡as del ferrocarril, la antigua Azucarera Ib├®rica, creada en 1899, y desde 1903 dentro de la Sociedad General Azucarera de Espa├▒a. Fue cerrada en 1963, y luego derribada. En su solar se construyeron varios equipamientos p├║blicos: IES, polideportivo municipal, centro de salud, y un parque. Fuente visual: Arxiu Nacional de Catalunya.', 1954, 1954, 1954, 'Anos 50', 'CASETAS', 41.72237400, -1.02844200, '0101000020E610000048533D997F74F0BF88BD50C076DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31409987540.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31409987540.webp', 'https://www.flickr.com/photos/zaragozaantigua/31409987540/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23127, 'Tres puentes 2003', 'Ef├¡mera toma del paso del Ebro por Zaragoza, con el puente del Ferrocarril (1968, demolido en 2007), entre el nuevo puente del AVE (2003) y el puente de Manuel Gim├®nez Abad (2002). Fuente: Zaragoza. Dos milenios de agua. Carlos Bl├ízquez, 2006.', 2003, 2003, 2003, 'Siglo XXI', 'LAS FUENTES', 41.65078900, -0.85334500, '0101000020E61000005890662C9A4EEBBF5CCCCF0D4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31446032806.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31446032806.webp', 'https://www.flickr.com/photos/zaragozaantigua/31446032806/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23774, 'Casetas 2007', 'Foto: Juan Carlos Arcos. Marzo de 2007. Posado de Roberto Polo (PSOE), alcalde del barrio rural zaragozano de Casetas, ante las obras de acondicionamiento de la antigua autov├¡a de Logro├▒o (N-232). Este vial atravesaba el barrio hasta la construcci├│n de la variante sur. El Estado cedi├│ el tramo a la ciudad en 1999. La conversi├│n en avenida de Logro├▒o tuvo lugar en varias fases, hasta 2010. A la derecha, calle de Arag├│n. Fuente: Heraldo de Arag├│n.', 2007, 2007, 2007, 'Siglo XXI', 'CASETAS', 41.71884400, -1.02809200, '0101000020E6100000BC77D4981073F0BF8176871403DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32100658472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32100658472.webp', 'https://www.flickr.com/photos/zaragozaantigua/32100658472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23775, 'Ctra. de Logro├▒o c.1985', 'Tal vez una de las ├║ltimas im├ígenes donde aparece la antigua y colosal fachada del desaparecido palacio del duque de Solferino, en la carretera de Logro├▒o a su paso por las Casetas. A la derecha del palacio, la iglesia parroquial del lugar, bajo la advocaci├│n de San Miguel Arc├íngel, y la decididamente contempor├ínea casa parroquial. A diferencia de otras im├ígenes anteriores en el tiempo, la carretera y el tr├ífico rodado son ya la nota protag├│nica del encuadre. Fuente visual: www.facebook.com/photo.php?fbid=10202474426124988&set...', 1985, 1985, 1985, 'Anos 80', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32673702394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32673702394.webp', 'https://www.flickr.com/photos/zaragozaantigua/32673702394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23783, 'Casetas 1986', 'En 1986 se produjeron movilizaciones vecinales en el barrio rural de Casetas, para pedir que la autov├¡a Zaragoza-Logro├▒o dejase de atravesar el casco urbano. La muerte por accidente de tr├ífico de un joven en mayo de ese a├▒o aviv├│ las protestas, con enfrentamientos con las fuerzas de orden, y el ministerio de Obras P├║blicas se comprometi├│ a construir una variante, que se materializ├│ la d├®cada siguiente. En la imagen, vecinas y vecinos del barrio cortan la carretera ante la presencia de la Guardia Civil, en el paso de peatones a la altura del perpendicular arranque de la calle de Am├®rica (a la izquierda), y la de Huesca (a la derecha). Al fondo y a la izquierda, vista del moderno inmueble del n┬║ 67-69 de la carretera, enfrente del cual, a la derecha y fuera de plano, se encontraba el ingreso principal al CMVR (Centro de Mantenimiento de Veh├¡culos a Rueda) de la 5┬¬ Regi├│n Militar, cuartel que fuera construido durante la guerra Civil de 1936-39 por prisioneros de guerra republicanos en suelo expropiado al municipio. Esta gran instalaci├│n militar tambi├®n ser├¡a luego reivindicada para ser revertida en beneficio de los habitantes del barrio. A pesar de las promesas electorales realizadas en este sentido por el candidato Belloch a la alcald├¡a de Zaragoza durante la campa├▒a de 2003, este cuartel actualmente sigue adscrito a la Agrupaci├│n de Apoyo Log├¡stico n┬║ 41 del Ej├®rcito.', 1986, 1986, 1986, 'Anos 80', 'CASETAS', 41.71823000, -1.02667400, '0101000020E6100000C1745AB7416DF0BFC780ECF5EEDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48693293411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48693293411.webp', 'https://www.flickr.com/photos/zaragozaantigua/48693293411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23787, 'Casetas 1970', 'Imagen de la azucarera de Casetas, un a├▒o antes de su derribo en 1971. Fue construida en 1899 y cerrada en 1965. Su solar lo ocupan hoy equipamientos p├║blicos.', 1970, 1970, 1970, 'Anos 70', 'CASETAS', 41.72237400, -1.02844200, '0101000020E610000048533D997F74F0BF88BD50C076DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54465720236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54465720236.webp', 'https://www.flickr.com/photos/zaragozaantigua/54465720236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23190, 'Castillo de Juslibol 2010', 'Foto: Jos├® Mar├¡a Ballest├¡n, 2010. Tambi├®n conocido como Picote de San Mart├¡n, el castillo de Juslibol se encuentra en las traseras de la poblaci├│n de este barrio rural de Zaragoza. De construcci├│n musulmana, en el marco de las fortificaciones que rodeaban Saraqusta, se denominaba Mezi Meeger. Pedro I se hizo con ├®l en 1101, en su campa├▒a contra la ciudad, redenomin├índolo con el grito guerrero de Deus lo vol (Dios lo quiere, derivado en Juslibol). En 2007 se derrumb├│ uno de sus muros. Fuente: peripaseos.wordpress.com/2010/05/22/si-juslibol-mira-y-anda/', 2010, 2010, 2010, 'Siglo XXI', 'JUSLIBOL', 41.69494300, -0.89373500, '0101000020E6100000444C89247A99ECBFC5CA68E4F3D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19247386753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19247386753.webp', 'https://www.flickr.com/photos/zaragozaantigua/19247386753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23241, 'Castillo de Juslibol s. XI', 'Reconstrucci├│n virtual de Daniel Herrera del estado original del castillo de Juslibol de Zaragoza. Fuente: deuslovol.blogspot.com.es/', 1050, 1000, 1099, 'Siglo XIX', 'JUSLIBOL', 41.69494300, -0.89373500, '0101000020E6100000444C89247A99ECBFC5CA68E4F3D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19681433990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19681433990.webp', 'https://www.flickr.com/photos/zaragozaantigua/19681433990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23199, 'Parque de Valdefierro 2010', 'Vista del parque de Valdefierro reci├®n construido en 2010. Se trata de un precioso entorno extraterrestre dise├▒ado por H├®ctor Fern├índez Elorza y ubicado a orillas del Canal Imperial (al fondo a la derecha), entre las calles Centauro e Hydra del barrio de Valdefierro. Sus gr├íciles muros cicl├│peos de hormig├│n armado le confieren las mismas caracter├¡sticas post apocal├¡pticas de los accesos al Parque Venecia, del mismo autor. A la izquierda se ve un fragmento de la urbanizaci├│n Torre Pajaritos. Rompiendo el horizonte, la torre de la Cooperativa de Autotaxi. Fuente visual: architettura-italiana.com/', 2010, 2010, 2010, 'Siglo XXI', 'OLIVER-VALDEFIERRO', 41.63614700, -0.92976200, '0101000020E61000009E08E23C9CC0EDBF6939D0436DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29321453682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29321453682.webp', 'https://www.flickr.com/photos/zaragozaantigua/29321453682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22071, 'TUDOR 1959', 'A├®rea imagen de las instalaciones de la TUDOR en la carretera de Navarra. En la neomud├®jar puerta de la factor├¡a, un tranv├¡a de la l├¡nea 16, y visual de la caseta del Portazgo, casi ya en la carretera de los Enlaces. Un poco a la izquierda, el puente por el que el ferrocarril del Caminreal pasaba por encima de la carretera de Logro├▒o para acceder al recorrido por Oliver-Valdefierro. En las traseras de la TUDOR, la plataforma giratoria del dep├│sito de locomotoras de Delicias, al lado de donde luego se levantar├¡an las naves del Dep├│sito de Tracci├│n Diesel. Cultivos de herb├íceas y un entorno periurbano. Los bloques de viviendas de primer plano configuraban el denominado "Barrio de las casas de la Caja de Ahorros". Tras su abandono, fueron ocupados como subviviendas, hasta su piqueteo final. Hoy, cerca se encuentra el Colegio P├║blico Jos├® Cam├│n Aznar y el IES Santiago Hern├índez.', 1959, 1959, 1959, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65974100, -0.92102300, '0101000020E610000051A4FB390579EDBF486AA16472D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15441332034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15441332034.webp', 'https://www.flickr.com/photos/zaragozaantigua/15441332034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23161, 'Ebro este 2007', 'Foto: Oliver Duch. Vista a├®rea del r├¡o Ebro a su paso por el este de la ciudad, en octubre de 2007. Abajo, el barrio de Las Fuentes. Sobre el lecho, el azud Manuel Lorenzo Pardo en construcci├│n, y los puentes de Manuel Gim├®nez Abad, el ferrocarril convencional y el AVE. Fuente: Heraldo de Arag├│n.', 2007, 2007, 2007, 'Siglo XXI', 'LAS FUENTES', 41.65177700, -0.85756000, '0101000020E6100000C5724BAB2171EBBF7BA4C16D6DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32523875495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32523875495.webp', 'https://www.flickr.com/photos/zaragozaantigua/32523875495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25111, 'La Seo 1909', '"Saragossa. La Seo", Collins, W. W.,1909. Fotograbado a color Fuente: "Cathedral cities of Spain".', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65463400, -0.87558800, '0101000020E61000003CA41820D104ECBFC26C020CCBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877794947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877794947.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877794947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22083, 'TUDOR c.1950', 'Imagen de la puerta principal de acceso a las nuevas instalaciones de la f├íbrica TUDOR en la carretera de Navarra, tras dejar atr├ís su primera ubicaci├│n al final de Sagasta, donde estuvo desde 1898 a 1946. Aqu├¡ estar├í desde 1946 a 1989, en que se trasladar├í a Malpica y La Cartuja Baja. La L├¡nea 16 del Tranv├¡a (Portazgo-San Lamberto) fue inaugurada en enero de 1952, con inicio en la Plaza de Espa├▒a y hasta unos pocos metros de esta puerta, entre otras razones, para dar servicio a los trabajadores de la factoria. Fuente: www.facebook.com/photo.php?fbid=853391044683522&set=g...', 1950, 1950, 1950, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65887700, -0.92174600, '0101000020E61000008A00A777F17EEDBF158BDF1456D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15799456898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15799456898.webp', 'https://www.flickr.com/photos/zaragozaantigua/15799456898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22130, 'Ctra. de los Enlaces 1959', 'Imagen publicitaria de una serie de nuevas unidades de autob├║s con chasis "Leyland", modelo "Royal Tiger Worldmaster", carrozados en Material M├│vil y Construcciones para los transportes urbanos de Sevilla. El posado ha sido realizado junto al reciente Grupo de Viviendas "Arzobispo Domenech", levantado en una ladera de pronunciada pendiente entre los barrios de Oliver (izquierda) y Delicias (derecha). Los cuatro bloques de la imagen (de los trece del conjunto) eran los recayentes a la carretera de los enlaces Logro├▒o-Madrid-Valencia. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1959, 1959, 1959, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65174500, -0.91951300, '0101000020E61000002EE6E786A66CEDBF6F2A52616CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23353679773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23353679773.webp', 'https://www.flickr.com/photos/zaragozaantigua/23353679773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22286, 'Avenida de Navarra 1967', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 22/10/1967. "Se├▒ales de velocidad en la entrada de Zaragoza." Estamos en la carretera de Navarra, a unos metros de la carretera de los enlaces, que contin├║a un poco antes hacia la derecha, y que a├▒os despu├®s ser├í denominada "V├¡a de la Hispanidad". A la izquierda, justo al otro lado de la carretera, quedan las enormes instalaciones de la TUDOR. A este lado, un r├│tulo avisa que esto ya es Zaragoza, junto a alguna referencia tur├¡stica (Aljafer├¡a, La Seo, y las Torres del Pilar), a un enorme cartel├│n dirigido a los transportistas, y detr├ís, el "Bar Fielato Caf├®", que recuerda la ubicaci├│n del "Fielato" u oficina donde los transportistas abonaban a├▒os ha una cierta cantidad en funci├│n de lo que transportaran de entrada en la ciudad. A mediados de marzo de ese mismo a├▒o hab├¡a sido clausurada la l├¡nea 16 de los tranv├¡as "Portazgo-San Lamberto", y ya no queda ni rastro de la terminal que hab├¡a en la puerta de la TUDOR. Al fondo, bien mirando, una torre del Pilar confirma lo correcto de las indicaciones de los carteles.', 1967, 1967, 1967, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65864500, -0.92207900, '0101000020E61000001F82AAD1AB81EDBF4356B77A4ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15197476976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15197476976.webp', 'https://www.flickr.com/photos/zaragozaantigua/15197476976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22391, 'Calle de Antonio Leyva 1969', 'La calle zaragozana Antonio de Leyva, antes de glorificar la memoria de este general del siglo XVI que muri├│ de un ataque de gota, fue veterano camino an├│nimo entre los caminos que surcaban el original barrio Oliver. Luego nominada "Le├│n Tolstoi" durante unos extra├▒os a├▒os, hasta que fue normalizada al espa├▒ol para castizos. Las humildes parcelas unifamiliares siguieron definiendo este entorno de la periferia pero bien lejana del lustroso "centro". La ciudad quedaba como a cuarenta a├▒os de distancia. La imagen ha sido capturada a la altura de la calle Lope de Vega, inmediata hacia la izquierda, y la siguiente, Tirso de Molina, tambi├®n, para que luego digan que no se tra├¡a cultura a los barrios. El suelo, terroso, y el sol a plomo invitan a tomar un refresco, aunque sea burbujeante, concentrado de az├║cares industriales, y la botellla la agite un inquietante duendecillo. Se recomienda pasear por el lado de las sombras, que adem├ís hay acera. Fuente visual: Archivo P├║blico Municipal.', 1969, 1969, 1969, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65197800, -0.92245300, '0101000020E6100000581B6327BC84EDBF12DBDD0374D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22734823449.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22734823449.webp', 'https://www.flickr.com/photos/zaragozaantigua/22734823449/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22762, 'Calle de Antonio Leyva 1978', 'Imagen del antiguo acceso al Barrio Oliver desde la calle de Antonio Leyva, por donde se interna el autob├║s urbano de la l├¡nea 21. A la derecha, entronque con la calle Alfred Nobel. Al fondo, el acceso a la antigua calle de Victor Hugo, redenominada "de la Victoria" nacionalista tras el 1 de abril de 1939, y que desde 2009 es denominada de ├üngela Bravo Ortega. Detr├ís, emerge el chaflanero edificio entre Antonio Leyva y la calle Espronceda. La tradicional urbanizaci├│n de esta zona de la ultraperiferia de la ciudad, a base de parcelas, y con un tr├ífico rodado muy ocasional, casi noticiable, a mediados de los a├▒os 70 del pasado siglo comenz├│ a chocar con la realidad de los nuevos tiempos que, literalmente, no encajaba por viales cuyo original dise├▒o no contemplaba la m├íxima "una persona, un coche". Tiempo despu├®s, el derribo de las parcelas laterales, y el retranqueamiento edilicio reconfigur├│ este espacio. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.65209000, -0.92195900, '0101000020E610000076172829B080EDBF3A0664AF77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33002966551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33002966551.webp', 'https://www.flickr.com/photos/zaragozaantigua/33002966551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22992, 'Tudor 1990', 'Foto: Eliseo Remolar. Aspecto del derribo de la f├íbrica de acumuladores Tudor, en la avenida Navarra de Zaragoza. Estuvo all├¡ desde 1946 hasta que fue vendida en 1989. Fuente: www.facebook.com/photo.php?fbid=847554898616334&set=g...', 1990, 1990, 1990, 'Anos 90', 'OLIVER-VALDEFIERRO', 41.65974100, -0.92102300, '0101000020E610000051A4FB390579EDBF486AA16472D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21658917265.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21658917265.webp', 'https://www.flickr.com/photos/zaragozaantigua/21658917265/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23017, 'Solar Tudor 1993', 'Terrenos abandonados por la f├íbrica de bater├¡as Tudor, vendidos en 1989 a la empresa constructora Sicione que proyect├│ sobre ellos un centro comercial. En 1991, durante el movimiento de tierras para desescombrar la zona, se detectaron concentraciones de elevadas plomo, adem├ís de trazas de cobre, zinc, n├¡quel y cadmio. En 1992 se llev├│ a cabo la presunta descontaminaci├│n de la zona, cuando los residuos t├│xicos fueron trasladados a un vertedero en el Acampo de P├®rez Baerla (La Cartuja Baja). de esta forma, comenz├│ la construcci├│n del proyectado centro comercial Augusta, inaugurado en 1995. La imagen ha sido capturada desde la altura del trazado viario de la l├¡nea de Caminreal poco antes de su a├®reo cruce sobre la carretera de Logro├▒o. Al fondo y a la derecha, ├║ltimos edificios de los impares de la avenida de Navarra y otros del barrio de la Bombarda-Monsalud.', 1993, 1993, 1993, 'Anos 90', 'OLIVER-VALDEFIERRO', 41.65991500, -0.92164900, '0101000020E6100000ED832C0B267EEDBFE6913F1878D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37931453996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37931453996.webp', 'https://www.flickr.com/photos/zaragozaantigua/37931453996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23672, 'Cuartel de San Lamberto 1966', 'Imagen del cl├¡max propio del antiguo ceremonial de la Jura de Bandera de reclutas del arma de Aviaci├│n en el acuartelamiento de San Lamberto, en el barrio de Miralbueno. El desfile se hac├¡a un poco cuesta arriba, por la orograf├¡a de la zona, en ascenso hasta los pronunciados taludes sobre los que se alza el barrio de Oliver, a la izquierda. Junto a la bandera del Arma presiden autoridades militares, religiosas, y aun bal├¡sticas. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65643500, -0.92855800, '0101000020E6100000AA0D4E44BFB6EDBF9279E40F06D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32115140102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32115140102.webp', 'https://www.flickr.com/photos/zaragozaantigua/32115140102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23687, 'Cuartel de San Lamberto 1999', 'Imagen capturada en el exterior del ingreso al abandonado cuartel de San Lamberto adscrito al Ej├®rcito del Aire, sito en el camino del Pil├│n (Miralbueno). Este cuartel estuvo activo desde 1963 y hasta 1993, cuando su personal fue trasladado a la Base A├®rea. En ├®l se realizaba la "reclutada" o los dos meses en los que se instru├¡a a los reclutas en nociones b├ísicas de orden cerrado, orden abierto y un escueto conocimiento de las armas del Ej├®rcito del Aire. Pasado este plazo se realizaba la Jura de Bandera y los ya soldados pasaban destinados a las diferentes unidades en que iban a realizar su servicio militar, que ser├¡a de diecis├®is meses para los soldados voluntarios y de doce meses para los de leva forzosa. En 2001 se firmar├¡a un convenio entre el ministerio de Defensa y el Ayuntamiento de Zaragoza para el traspaso de la propiedad de estos terrenos, que fueron subastados poco despu├®s para la construcci├│n de bloques de viviendas y equipamientos del barrio de Miralbueno.', 1999, 1999, 1999, 'Anos 90', 'OLIVER-VALDEFIERRO', 41.65837200, -0.92851600, '0101000020E6100000EF01BA2F67B6EDBF124DA08845D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50514222336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50514222336.webp', 'https://www.flickr.com/photos/zaragozaantigua/50514222336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23691, 'Tudor c.1979', 'F├íbrica de bater├¡as Tudor, en la avenida de Navarra. Hoy los terrenos est├ín ocupados por el centro comercial Augusta, tras ser comprados a la empresa en 1989 por 2.000 millones de pesetas. En 1992 se descubri├│ que el solar estaba altamente contaminado de plomo. Unos cuantos viajes de camiones con la tierra y solucionado.', 1979, 1979, 1979, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.65974100, -0.92102300, '0101000020E610000051A4FB390579EDBF486AA16472D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14924388752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14924388752.webp', 'https://www.flickr.com/photos/zaragozaantigua/14924388752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23700, 'Enlace de Carreteras 1962', 'En el entonces lejan├¡simo Enlace de Carreteras, anexo a unas recientes viviendas sindicales del barrio Oliver, una caja de ahorros local impuls├│ la erecci├│n de una guarder├¡a infantil, comandada por una comunidad de monjas. Tras haberse reinventado el Arco del De├ín, del mismo patr├│n, Teodoro R├¡os Us├│n dise├▒├│ en 1957 este edificio. Lo hizo sumando un cl├ísico pabell├│n prism├ítico (acceso, recepci├│n, servicios comunitarios, dormitorios), y otro m├ís innovador, en forma de abanico desplegado (aulas, salas de juego a cubierto, comedor). Completa el conjunto una estructura voladiza en una zona de vegetaci├│n y jardines para juegos al aire libre, am├®n de una confesional capilla. Con el tiempo, la "guarder├¡a" se convirti├│ en "Escuela de Educaci├│n Infantil", y ahora anuncia ser un privado bosque lleno de ternura. En la imagen, las criaturas y las monjas en los jardines guarderiles. A la derecha, el edificio principal y el aulario. A la izquierda, el voladizo. A la espalda del fot├│grafo, la carretera de los Enlaces, que tres a├▒os despu├®s ser├í redenominada "V├¡a de la Hispanidad". Tras los ├írboles del fondo, el barrio Oliver.', 1962, 1962, 1962, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65388300, -0.92082300, '0101000020E61000008CF2CCCB6177EDBF87342A70B2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16480862154.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16480862154.webp', 'https://www.flickr.com/photos/zaragozaantigua/16480862154/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23715, 'Av. de Navarra 1965', 'Colorista imagen capturada en el bucle del final de la tranviaria l├¡nea 16 "Portazgo San Lamberto" y centrada en la unidad n┬║ 166 (un "topolino") en servicio ordinario, encaminada de vuelta hacia la avenida de Madrid, que es s├íbado y en s├íbado se baja a Zaragoza a pasar la tarde. Un par de a├▒os m├ís tarde esta l├¡nea fue clausurada, y el tranv├¡a fue luego vendido a la urbanizaci├│n El Frasno. Al fondo, ingreso principal de la gran f├íbrica de la Sociedad Espa├▒ola del Acumulador Tudor en sus instalaciones de la avenida de Navarra desde 1946, principal cliente de la l├¡nea 16 en una zona con muy poca poblaci├│n.', 1965, 1965, 1965, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65887700, -0.92174600, '0101000020E61000008A00A777F17EEDBF158BDF1456D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27388888317.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27388888317.webp', 'https://www.flickr.com/photos/zaragozaantigua/27388888317/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24209, 'Ctra. de Logro├▒o 1933', 'Imagen del nuevo puente tendido sobre la carretera de Logro├▒o por el que transitaba el ferrocarril de Caminreal en la zona del Portazgo. Al fondo, otro nuevo puente de paso para realizar un enlace ferroviario con la l├¡nea de Alsasua, proyecto que qued├│ sin finalizar. El tama├▒o del ojo del puente indica el volumen de tr├ínsito de cualquier tipo (en ambas direcciones) que la carretera de Logro├▒o soportaba al principio de la d├®cada de los a├▒os treinta. En el momento de tirar la fotograf├¡a, un ramoneante reba├▒o de cabras, y un carro tirado por caballer├¡a que traquetea hacia Zaragoza. Hacia la izquierda, acceso a los barrios de Oliver y Valdefierro. Hacia la derecha, descenso en curva hacia la nueva estaci├│n de Caminreal, del Ferrocarril Central de Arag├│n, o Delicias. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'OLIVER-VALDEFIERRO', 41.65959800, -0.92448300, '0101000020E6100000ADA7565F5D95EDBFE6400FB56DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36677758615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36677758615.webp', 'https://www.flickr.com/photos/zaragozaantigua/36677758615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24834, 'Iglesia de la Asunci├│n 1943', 'Dibujo de Ambrosio Ruste representando la fachada de la iglesia de la Asunci├│n de Nuestra Se├▒ora, entonces patrona del barrio Oliver de Zaragoza. Perteneci├│ a la jurisdicci├│n de la parroquia de San Valero desde 1942. En los a├▒os 80 del siglo XX, fue utilizada como Casa de Juventud. Hoy permanece en pie (sin la torre) albergando la Asociaci├│n de Vecinos del Barrio Oliver, en la calle de Pilar Aranda 24. Fuente: ┬íAqu├¡... Zaragoza!, Jos├® Blasco Ijazo, 1953.', 1943, 1943, 1943, 'Anos 40', 'OLIVER-VALDEFIERRO', 41.65131700, -0.92210100, '0101000020E6100000137CD3F4D981EDBF172AFF5A5ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19856849175.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19856849175.webp', 'https://www.flickr.com/photos/zaragozaantigua/19856849175/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24836, 'Calle de Antonio de Leyva 1963', 'Calle de Antonio de Leyva en el barrio del Oliver, con los muretes del colegio p├║blico Fernando el Cat├│lico a la derecha. Al fondo, tras los autobuses, la intersecci├│n con la calle de San Vicente Ferrer. Fuente: www.facebook.com/photo.php?fbid=10206422084136537&set...', 1963, 1963, 1963, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65162000, -0.92712300, '0101000020E610000031D28BDAFDAAEDBFB3B5BE4868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29581899284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29581899284.webp', 'https://www.flickr.com/photos/zaragozaantigua/29581899284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24837, 'La Asunci├│n 1957', 'Imagen del interior de la antigua iglesia parroquial de Ntra. Sra. de la Asunci├│n, patrona del barrio Oliver, que fue construida seg├║n proyecto de Regino Borobio redactado en 1937, en la calle del Progreso Espa├▒ol n┬║ 24. En 1982, el edificio pas├│ a propiedad municipal, que lo reform├│ para albergar la Casa del Juventud del barrio, y la grey de Oliver qued├│ reasignada a las nuevas iglesias parroquiales de San Pedro Ap├│stol (donde fue trasladado el icono de la Asunci├│n), en la plaza de Lolita Parra, y la de la Coronaci├│n de la Virgen, en la calle de Cetina. La fotograf├¡a se ha realizado desde la entrada a la iglesia, con despejada visual de su planta basilical de testero recto, que se abre al fondo, para albergar el altar ceremonial, e incluye un acceso a la sacrist├¡a, hacia la derecha. Fuente visual: Archivo Coyne, AHPZ.', 1957, 1957, 1957, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65131700, -0.92210100, '0101000020E6100000137CD3F4D981EDBF172AFF5A5ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30952752142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30952752142.webp', 'https://www.flickr.com/photos/zaragozaantigua/30952752142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24839, 'Barrio Oliver 1955', 'Vista a├®rea centrada en las nuevas viviendas del Grupo General Urrutia, en el barrio Oliver. Ante ellas, cruza lo que ser├í la calle Antonio de Leyva. Abajo, el dep├│sito de agua en construcci├│n, en la calle San Vicente Ferrer. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65206900, -0.92888300, '0101000020E610000089EE59D768B9EDBF22DE3AFF76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31323769906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31323769906.webp', 'https://www.flickr.com/photos/zaragozaantigua/31323769906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24840, 'Grupo Arzobispo Domenech 1955', 'Vista a├®rea centrada en el Grupo de Viviendas Arzobispo Domenech, construido en 1955 en el barrio Oliver, junto a la carretera de Los Enlaces (hoy avenida de la Hispanidad). Abajo, fuera de plano, Los Enlaces. Arriba, la curva hacia la carretera de Logro├▒o. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65223700, -0.92007400, '0101000020E610000003CC7C073F71EDBFDE1E84807CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31359708165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31359708165.webp', 'https://www.flickr.com/photos/zaragozaantigua/31359708165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24845, 'Barrio Oliver c.1959', 'Imagen del reciente grupo de viviendas del "General Urrutia" impulsado en la segunda mitad de los a├▒os cincuenta por la Obra Sindical del Hogar en la barriada de Oliver. Proyectado en dos fases por los arquitectos Fausto Garc├¡a Marco y Alejandro Allanegui F├®lez, la fotograf├¡a muestra una vista del conjunto tomada m├ís all├í de las agrestes inmediaciones al final de la prolongada calle de Antonio de Leyva.', 1959, 1959, 1959, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65182300, -0.92965300, '0101000020E6100000EF1AF4A5B7BFEDBFEBE3A1EF6ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53673979605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53673979605.webp', 'https://www.flickr.com/photos/zaragozaantigua/53673979605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26000, 'La Bombarda 1994', 'Foto: Archivo Taumar (Irene Taul├®s y Rafael Margal├®). Vista a├®rea del barrio de La Bombarda (derecha) en la confluencia de la avenida de Navarra (centro) con la V├¡a Hispanidad (abajo). Al fondo, el r├¡o Ebro. Fuente: www.facebook.com/photo.php?fbid=1687674311456268&set=...', 1994, 1994, 1994, 'Anos 90', 'OLIVER-VALDEFIERRO', 41.65811500, -0.92072800, '0101000020E61000001C5E10919A76EDBFE700C11C3DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21787448103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21787448103.webp', 'https://www.flickr.com/photos/zaragozaantigua/21787448103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26068, 'V├¡a de la Hispanidad 1991', 'Imagen capturada desde la altura del inmueble del n┬║ 152 de la V├¡a de la Hispanidad y centrada en el veterano enlace de carreteras que conectaba la avenida de Navarra (desde la derecha), la V├¡a de la Hispanidad y la carretera de Logro├▒o (a la izquierda), y que adem├ís daba acceso por el camino del Pil├│n, antiguo de Miralbueno, a este hom├│nimo barrio por donde en la fotograf├¡a se introduce un autob├║s. A la derecha, vista parcial del enorme solar de 111.000 metros cuadrados dejado por la f├íbrica Tudor tras su traslado a Malpica y la Cartuja Baja, donde entre 1993 y 1995 el Grupo Sicione construir├í una nueva gran superficie comercial con tiendas, cines, centro comercial, bares y restaurantes. En 1993 el Ayuntamiento solicitar├¡a al Ministerio de Obras P├║blicas, Transportes y Medio Ambiente, al objeto de mejorar la conectividad del creciente tr├ífico en esta zona, la construcci├│n de un nuevo nudo de conexi├│n que se basar├¡a en un entramado de puentes en altura inaugurado en 1996 y que por la cercan├¡a del referido centro comercial, recibir├¡a la denominaci├│n de Nudo de Sicione.', 1991, 1991, 1991, 'Anos 90', 'OLIVER-VALDEFIERRO', 41.65854900, -0.92192800, '0101000020E6100000B58828266F80EDBF21E868554BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50447041827.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50447041827.webp', 'https://www.flickr.com/photos/zaragozaantigua/50447041827/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21468, 'Campo de concursos c.1913', 'En 1909 fue constituida la elitista "sociedad sportiva La H├¡pica Aragonesa", con un picadero al principio de la calle de Felipe Sanclemente y mano suficiente para conseguir que el cuartel de los Lanceros del Rey le permitiera usar su pista de ejercicios para organizar sus primeros concursos h├¡picos. A comienzos de 1910 adquiri├│ a Emilio Burbano 23.000 metros cuadrados de terreno con entrada por la carretera de Madrid a Francia donde habilitaron un campo de concursos h├¡picos y una pista de entrenamiento y juegos de "sport". Al mismo tiempo, adquirieron un espacio m├ís peque├▒o en el paseo de los Pl├ítanos para nuevo picadero donde impartir clases de equitaci├│n a caballeros, se├▒oritas de familia bien y ni├▒os mayores de diez a├▒os. Los concursos h├¡picos organizados por La H├¡pica lograron incrustarse en el programa de las fiestas del Pilar de esta d├®cada como una atracci├│n m├ís para el p├║blico, si bien en este caso se trataba del p├║blico "m├ís selecto y distinguido" de la "buena sociedad" de la ├®poca. En la imagen, un caballo salta uno de los obst├ículos que formaban parte del recorrido de este hip├│dromo, que en ocasiones logr├│ atraer a algunos de los m├ís destacados jinetes del momento, generalmente militares, arist├│cratas o miembros de la nobleza, pugnando por trofeos muy cotizados como los que patrocinaban los infantes reales o el propio monarca, y premios en met├ílico de hasta 2.700 pesetas.', 1913, 1913, 1913, 'Anos 10', 'OLIVER-VALDEFIERRO', 41.64960300, -0.91712200, '0101000020E6100000C8258E3C1059EDBF1631EC3026D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53461257715.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53461257715.webp', 'https://www.flickr.com/photos/zaragozaantigua/53461257715/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25127, 'Puerto de Zaragoza 1983', '"Fantas├¡a fotogr├ífica", Gracia, 1933. Los delirios sobre la navegabilidad del Ebro en el siglo vig├®simo inclu├¡an proyectos de global encementamiento portland del cauce, y su conversi├│n en canal├│n de proporciones mesopot├ímicas, s├¡mil terr├íqueo de uno de esos m├¡ticos canales artificiales marcianos. Y para los casos de riada, o salida de madre, a dragar y hacer m├ís hondo y ancho el cauce, para que as├¡ cupiera m├ís agua, cogiera m├ís velocidad, y arrasara mejor. S├│lo la falta de inmensos presupuestos frenaron la realizaci├│n de esas l├║cidas ideas. La presente imagen es un fantasioso fotomontaje de 1933 que proyectaba hacia el futuro las mutaciones gen├®ticas que presentar├¡a Zaragoza en 1983, en su fachada ribere├▒a, de mediar un Ebro navegable desde el Cant├íbrico al Mediterr├íneo. El resultado es espectacular. Zaragoza convertida en una meridional Londres, con el mega Paseo del Ebro como bullicioso frente portuario atestado de embarcaciones e ingenios flotantes que le dan un rabioso aspecto cosmopolita y metropolitano. La fauna que poblar├¡a las inmediaciones dar├¡a para escribir varias novelas, y de las largas. Los puentes, incluyendo alguno levadizo, cuartean el horizonte acu├ítico, y en las orillas no faltan las mec├ínicas gr├║as de carga y descarga. Alg├║n rascacielos s├¡ que se echa en falta, pero esta Zaragoza no hubiera necesitado una Expo internacional para volcarse al r├¡o que la vio nacer, y es posible que los desarrollos urban├¡sticos y las planificaciones de crecimiento hubieran sido otros muy distintos... Mas esta fantas├¡a es prisionera de su tiempo: el templo del Pilar tiene las dos torres reglamentarias de 1933. La desbordada imaginaci├│n no daba para prever que alguien querr├¡a construir las otras dos. Eso s├¡ parec├¡a delirante: por aquellos a├▒os, la navegabilidad del r├¡o consist├¡a en el artesanal descenso de almadieros desde los norte├▒os valles pirenaicos, para traer madera a la ciudad. Desde el inicio de la implantaci├│n del ferrocarril, a mediados del XIX, la navegabili', 1983, 1983, 1983, 'Anos 80', 'CASCO HIST├ôRICO', 41.65473300, -0.86856300, '0101000020E61000003080F0A144CBEBBF554E7B4ACED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16465731497.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16465731497.webp', 'https://www.flickr.com/photos/zaragozaantigua/16465731497/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
